def update_model_svg(arch_name):
    if arch_name == "SwinTransformerTex": 
        return get_transformer_svg()
    elif arch_name == "SwinGConvTex": 
        return get_gconv_svg()
    elif arch_name == "SwinMoETex": 
        return get_moe_svg()
    return get_mamba_svg()